document.addEventListener("alpine:init",()=>{Alpine.data("inlineConfirmAction",({timeout:t,isGrouped:i=!1,shouldCloseDropdown:s=!0})=>({armed:!1,processing:!1,timer:null,arm(){this.armed=!0,this.timer=setTimeout(()=>this.disarm(),t)},disarm(){clearTimeout(this.timer),this.armed=!1,this.processing=!1},process(){clearTimeout(this.timer),this.processing=!0,this.closeDropdown()},closeDropdown(){if(!i||!s)return;let e=this.$el.closest('[x-data*="filamentDropdown"]');e&&Alpine.$data(e).close()}})),Alpine.data("holdToConfirmAction",({duration:t,isGrouped:i=!1,shouldCloseDropdown:s=!0})=>({holding:!1,processing:!1,timer:null,start(){this.processing||(this.holding=!0,this.timer=setTimeout(()=>this.complete(),t))},cancel(){!this.holding||this.processing||(clearTimeout(this.timer),this.holding=!1)},complete(){clearTimeout(this.timer),this.holding=!1,this.processing=!0,this.closeDropdown(),this.$el.dispatchEvent(new CustomEvent("htc-complete",{bubbles:!0}))},done(){this.processing=!1},closeDropdown(){if(!i||!s)return;let e=this.$el.closest('[x-data*="filamentDropdown"]');e&&Alpine.$data(e).close()}}))});
